class Solution:
    def maxSubarrays(self, n, conflictingPairs):
        m = len(conflictingPairs)
        def count_valid(active):
            cnt = 0
            bad = 0
            for r in range(1, n + 1):
                for a, b in active:
                    lo, hi = min(a, b), max(a, b)
                    if hi == r and lo > bad:
                        bad = lo
                cnt += r - bad
            return cnt
        best = 0
        for skip in range(m):
            active = [conflictingPairs[i] for i in range(m) if i != skip]
            best = max(best, count_valid(active))
        return best

