class Solution:
    def maxSubarrays(self, n, conflictingPairs):
        byq = [[] for _ in range(n + 1)]
        for idx, pair in enumerate(conflictingPairs):
            a, b = pair[0], pair[1]
            p, q = (a, b) if a < b else (b, a)
            byq[q].append((p, idx))
        curmax = 0
        second = 0
        cnt_curmax = 0
        owner = None
        credit = {}
        baseline = 0
        for r in range(1, n + 1):
            for p, idx in byq[r]:
                if p > curmax:
                    second = curmax
                    curmax = p
                    cnt_curmax = 1
                    owner = idx
                elif p == curmax:
                    cnt_curmax += 1
                    owner = None
                else:
                    if p > second:
                        second = p
            baseline += (r - curmax)
            if cnt_curmax == 1 and owner is not None:
                credit[owner] = credit.get(owner, 0) + (curmax - second)
        best_gain = 0
        for g in credit.values():
            if g > best_gain:
                best_gain = g
        return baseline + best_gain

