var maxSubarrays = function(n, conflictingPairs) {
    const byq = Array.from({ length: n + 1 }, () => []);
    conflictingPairs.forEach((pair, idx) => {
        const a = pair[0], b = pair[1];
        const p = Math.min(a, b), q = Math.max(a, b);
        byq[q].push([p, idx]);
    });
    let curmax = 0, second = 0, cntCurmax = 0, owner = -1;
    const credit = new Map();
    let baseline = 0;
    for (let r = 1; r <= n; r++) {
        for (const [p, idx] of byq[r]) {
            if (p > curmax) {
                second = curmax;
                curmax = p;
                cntCurmax = 1;
                owner = idx;
            } else if (p === curmax) {
                cntCurmax++;
                owner = -1;
            } else if (p > second) {
                second = p;
            }
        }
        baseline += (r - curmax);
        if (cntCurmax === 1 && owner !== -1) {
            credit.set(owner, (credit.get(owner) || 0) + (curmax - second));
        }
    }
    let bestGain = 0;
    for (const g of credit.values()) {
        if (g > bestGain) bestGain = g;
    }
    return baseline + bestGain;
};
